var apiKey = getVar('openai_api_key');
if (!apiKey) return JSON.stringify({error: "OpenAI API key not configured. Set the 'openai_api_key' variable."});

var size = args.size || '1024x1792';
var style = args.style || 'vivid';

var payload = JSON.stringify({
  model: 'dall-e-3',
  prompt: args.prompt,
  n: 1,
  size: size,
  style: style,
  response_format: 'url'
});

var resp = httpPost('https://api.openai.com/v1/images/generations', payload, {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json'
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'DALL-E API error (HTTP ' + resp.status + '): ' + errBody});
}

var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;
var result = data.data[0];

return JSON.stringify({
  image_url: result.url,
  revised_prompt: result.revised_prompt
}, null, 2);

var apiKey = getVar('openai_api_key');
if (!apiKey) return JSON.stringify({error: "OpenAI API key not configured. Set the 'openai_api_key' variable."});

var size = args.size || '1024x1792';
var results = [];

for (var i = 0; i < args.scenes.length; i++) {
  var scene = args.scenes[i];
  var style = scene.style || 'vivid';

  var payload = JSON.stringify({
    model: 'dall-e-3',
    prompt: scene.prompt,
    n: 1,
    size: size,
    style: style,
    response_format: 'url'
  });

  try {
    var resp = httpPost('https://api.openai.com/v1/images/generations', payload, {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json'
    });

    if (resp.status !== 200) {
      var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
      results.push({
        scene_index: i,
        success: false,
        error: 'DALL-E API error (HTTP ' + resp.status + '): ' + errBody
      });
    } else {
      var data = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;
      var imgResult = data.data[0];
      results.push({
        scene_index: i,
        success: true,
        image_url: imgResult.url,
        revised_prompt: imgResult.revised_prompt
      });
    }
  } catch (e) {
    results.push({
      scene_index: i,
      success: false,
      error: 'Exception: ' + e.toString()
    });
  }
}

return JSON.stringify(results, null, 2);
